return [{ json: { ...ctx, subflow: 'BONIFICACIONES_INGEST' } }];

// BONIF - Parse IBI/ICIO + fallback IA + completado por fila
const ctx = $('INIT â€” Env & Config').first().json;
const data = $input.first().json;
let rows = Array.isArray(data) ? data : data.bonificaciones || data.data || [];

function parsePct(v) {
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : 0;
}

function parseYears(v) {
  const n = parseInt(v, 10);
  return Number.isFinite(n) ? n : 0;
}

function normalizeTipo(v) {
  return String(v || '').trim().toUpperCase();
}

async function aiBonifFallback() {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Devuelve JSON valido.' },
          { role: 'user', content: 'Genera 120 registros de bonificaciones municipales en Espana con campos municipio, provincia, tipo(IBI|ICIO), porcentaje_bonificacion, anios_bonificacion, condiciones. Devuelve {"items":[...]}.' }
        ]
      },
      json: true
    });
    const content = resp.choices?.[0]?.message?.content || '{}';
    return JSON.parse(content).items || [];
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'BONIF_AI_FALLBACK_ERROR', error: e.message }));
    return [];
  }
}

async function aiCompleteBonifRow(row) {
  if (!ctx.AI_API_KEY) return null;
  try {
    const prompt = 'Completa SOLO campos faltantes para bonificacion municipal en Espana. Devuelve {"item":{municipio,provincia,tipo,porcentaje_bonificacion,anios_bonificacion,condiciones}}. Entrada: ' + JSON.stringify(row);
