      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Rellena solo faltantes y mantente conservador.' },
          { role: 'user', content: prompt }
        ]
      },
      json: true
    });
    const content = resp.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    return parsed.item || parsed;
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'BONIF_AI_ROW_ENRICH_ERROR', error: e.message }));
    return null;
  }
