    return [];
  }
  rows = aiRows;
}

const ibi = [];
const icio = [];
const dead = [];
let aiRowEnriched = 0;
const MAX_AI_ROW_ENRICH = 80;

for (const row of rows) {
  let municipio = String(row.municipio || '').trim();
  let provincia = String(row.provincia || '').trim();
  let tipo = normalizeTipo(row.tipo);
  let porcentaje = parsePct(row.porcentaje_bonificacion || row.porcentaje);
  let duracion = parseYears(row.anios_bonificacion || row.duracion_anos || row.anios);
  let condiciones = String(row.condiciones || '').trim();

  const needsAi = !municipio || !provincia || !tipo || (!porcentaje && !duracion && !condiciones);
  if (needsAi && ctx.AI_API_KEY && aiRowEnriched < MAX_AI_ROW_ENRICH) {
    const ai = await aiCompleteBonifRow({ municipio, provincia, tipo, porcentaje_bonificacion: porcentaje, anios_bonificacion: duracion, condiciones, raw: row });
