      municipio = municipio || String(ai.municipio || '').trim();
      provincia = provincia || String(ai.provincia || '').trim();
      tipo = tipo || normalizeTipo(ai.tipo);
      porcentaje = porcentaje || parsePct(ai.porcentaje_bonificacion || ai.porcentaje);
