    url: `${ctx.SUPABASE_URL}/rest/v1/municipios_energia?select=municipio,provincia,slug,irradiacion_kwh_m2,precio_kwh&limit=10000`,
    headers: {
      'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY,
      'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`
    }
  });

  const municipios = Array.isArray(data) ? data : [];
  const estimaciones = municipios.map(m => ({
    municipio: m.municipio,
    provincia: m.provincia,
    slug: m.slug,
    // Asume instalaciÃ³n 4kWp estÃ¡ndar
    potencia_instalada_kwp: 4,
    produccion_anual_kwh: (m.irradiacion_kwh_m2 || 1300) * 4 * 0.80,
    precio_kwh_referencia: m.precio_kwh || 0.15,
    ahorro_bruto_anual_eur: Math.round((m.irradiacion_kwh_m2 || 1300) * 4 * 0.80 * (m.precio_kwh || 0.15)),
    payback_estimado_anios: Math.round(6000 / ((m.irradiacion_kwh_m2 || 1300) * 4 * 0.80 * (m.precio_kwh || 0.15))),
    actualizado_en: new Date().toISOString()
  }));

  // Upsert en lotes de 500
  for (let i = 0; i < estimaciones.length; i += 500) {
    const batch = estimaciones.slice(i, i + 500);
    await $helpers.httpRequest({
      method: 'POST',
      url: `${ctx.SUPABASE_URL}/rest/v1/estimaciones_ahorro_anual_es`,
      headers: {
        'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY,
        'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'resolution=merge-duplicates,return=minimal'
      },
      body: JSON.stringify(batch)
    });
  }

  console.log(JSON.stringify({ stage: 'ESTIMACIONES_UPSERT', count: estimaciones.length }));
} catch (e) {
  console.error(JSON.stringify({ stage: 'ESTIMACIONES_ERROR', error: e.message }));
}

return [{ json: ctx }];
